const hexName = (lines) => { // lines: 아래→위, 각 6~9
  const bit = (v) => (v % 2 ? "1" : "0");
  const lo = lines.slice(0, 3).map(bit).join(""), up = lines.slice(3).map(bit).join("");
  return HEX_NAMES[TRI_EL[up] + TRI_EL[lo]];
};

